package duckgo

import (
	"encoding/base64"
	"fmt"
	"testing"
)

// TestGenerateVQDHashWithRealChallenge 用真实 challenge 测试 VQD hash 生成
func TestGenerateVQDHashWithRealChallenge(t *testing.T) {
	vqdHash := ""
	
	result, err := GenerateVQDHash(vqdHash)
	if err != nil {
		t.Fatalf("GenerateVQDHash failed: %v", err)
	}
	
	// 解码结果检查结构
	decoded, err := base64.StdEncoding.DecodeString(result)
	if err != nil {
		t.Fatalf("decode result failed: %v", err)
	}
	
	t.Logf("result: %s", string(decoded))
	fmt.Printf("X-Vqd-Hash-1: %s\n", result)
}
